begin
  -- Host on the EXISTING council dummy (Redgum Shire Council). Kept completely
  -- separate from the convention-centre dummy - this seed never touches that org.
  select id into v_org from organisations where name ilike '%shire council%' and org_type = 'authority' order by created_at limit 1;
  if v_org is null then
    select id into v_org from organisations where name ilike '%shire council%' order by created_at limit 1;
  end if;
  if v_org is null then
    -- Fallback: no council dummy yet - create Redgum Shire Council and attach the
    -- existing demo user so it is viewable. (Skipped when your council org exists.)
    select om.user_id into v_user
      from organisation_memberships om join organisations o on o.id = om.organisation_id
     where om.status = 'active' order by om.created_at limit 1;
    if v_user is null then
      raise exception 'No demo user found - create the Redgum Shire Council org (or run a demo seed) first.';
    end if;
    insert into organisations (name, slug, org_type, parent_org_id, contact_email, allow_domain_auto_join, max_members)
    values ('Redgum Shire Council', 'redgum-shire-council', 'authority', null, 'access@redgum.sa.gov.au', false, 50)
    returning id into v_org;
    insert into organisation_memberships (organisation_id, user_id, role, status)
    values (v_org, v_user, 'admin', 'active')
    on conflict (organisation_id, user_id) do update set role = 'admin', status = 'active';
  else
    update organisations set org_type = 'authority' where id = v_org and org_type <> 'authority';
  end if;
  select name into v_name from organisations where id = v_org;

  insert into authority_programs
    (organisation_id, name, slug, description, required_module_ids, access_level,
     starts_at, ends_at, allow_self_enrol, is_active, funding_model, license_price_cents, enrol_message)
  values
    (v_org, 'Regional Tourism Accessibility Grant', 'tourism-accessibility-grant',
     'A grant-funded accessibility uplift for local tourism businesses. Each recipient completes a short accessibility assessment across the visitor journey so the council can target shared training, guidance and funding.',
     v_mods, 'pulse', now() - interval '90 days', now() + interval '270 days',
     true, true, 'authority_funded', null,
     'As a condition of the accessibility grant, please complete this short assessment. It takes about 20 minutes. Your individual responses stay private; the council only sees aggregate results.')
  on conflict (organisation_id, slug) do update
    set name = excluded.name, description = excluded.description,
        required_module_ids = excluded.required_module_ids, access_level = excluded.access_level,
        starts_at = excluded.starts_at, ends_at = excluded.ends_at, is_active = excluded.is_active,
        funding_model = excluded.funding_model, enrol_message = excluded.enrol_message, updated_at = now();
  select id into v_prog_id from authority_programs where organisation_id = v_org and slug = 'tourism-accessibility-grant';

  for v_rec in
    select * from (values
      ('Coastal Cafe','completed',58),
      ('Harbourview Gallery','completed',55),
      ('Riverland Cellar Door','completed',62),
      ('Summit Adventure Tours','completed',49),
      ('Bluestone Boutique Stay','completed',71),
      ('The Old Mill Museum','completed',66),
      ('Seabreeze Holiday Park','completed',53),
      ('Kanga Wildlife Sanctuary','completed',60),
      ('Vineyard Cycle Hire','completed',44),
      ('Portside Seafood Kitchen','completed',68),
      ('Heritage Walking Tours','completed',51),
      ('Lighthouse Visitor Centre','completed',57),
      ('Marina Kayak Co','in_progress',22),
      ('Foothills Farm Stay','in_progress',16)
    ) as t(biz_name, enrol_status, days_ago)
  loop
    select id into v_child from organisations where parent_org_id = v_org and name = v_rec.biz_name limit 1;
    if v_child is null then
      v_slug := regexp_replace(lower(v_rec.biz_name), '[^a-z0-9]+', '-', 'g');
      v_slug := regexp_replace(v_slug, '(^-|-$)', '', 'g') || '-grant';
      insert into organisations (name, slug, org_type, parent_org_id, contact_email, allow_domain_auto_join, max_members)
      values (v_rec.biz_name, v_slug, 'standard', v_org,
              'access@' || regexp_replace(regexp_replace(lower(v_rec.biz_name), '[^a-z0-9]+', '', 'g'), '(^-|-$)', '', 'g') || '.com.au',
              false, 10)
      returning id into v_child;
    end if;

    v_enrolled := now() - (v_rec.days_ago || ' days')::interval;
    if v_rec.enrol_status = 'completed' then
      v_submitted := now() - (greatest(v_rec.days_ago / 3, 4) || ' days')::interval;
      v_completed := now() - (greatest(v_rec.days_ago / 5, 2) || ' days')::interval;
    else
      v_submitted := null; v_completed := null;
    end if;

    insert into program_enrolments (program_id, organisation_id, status, enrolled_at, submitted_at, completed_at)
    values (v_prog_id, v_child, v_rec.enrol_status, v_enrolled, v_submitted, v_completed)
    on conflict (program_id, organisation_id) do update
      set status = excluded.status, enrolled_at = excluded.enrolled_at,
          submitted_at = excluded.submitted_at, completed_at = excluded.completed_at, updated_at = now();

    v_mi := 0;
    foreach v_mod in array v_mods loop
      v_cell := v_data -> (v_rec.biz_name || '::' || v_mod);
      -- in_progress businesses only have data for the modules present in v_data
      if v_cell is null then v_mi := v_mi + 1; continue; end if;
      v_mstatus := 'completed';
      insert into module_progress
        (session_id, module_id, module_code, status, confidence_snapshot, summary,
         started_at, completed_at, organisation_id, site_id, user_id, last_modified_by_user_id)
      values
        ('grant-' || v_child || '-' || v_mod, v_mod, v_mod, 'completed', v_cell ->> 'conf', v_cell -> 'summary',
         v_enrolled + interval '1 day', coalesce(v_completed, now() - interval '5 days'),
         v_child, null, null, null)
      on conflict (organisation_id, site_id, module_id) do update
        set status = excluded.status, confidence_snapshot = excluded.confidence_snapshot,
            summary = excluded.summary, started_at = excluded.started_at,
            completed_at = excluded.completed_at, updated_at = now();
      v_mi := v_mi + 1;
    end loop;
  end loop;

  raise notice 'Regional Tourism Accessibility Grant seeded on %: 14 businesses (12 completed, 2 in progress). Generate a report from Authority Portal > Programs > Regional Tourism Accessibility Grant.', v_name;
end $$;
